        if (instance == null)
        {
            instance = this;
        }

    }
    public void changescore(int StarValue)
    {
        score += StarValue;
        ScoreText.text = "Stars: " + score.ToString();
        if (score == winAmount)
        {
            winlosescript.Winlevel();
        }
    }
    private void Update()
    {
        Timer.text = Time.time.ToString("0.0");
    }


}

